      "heading": "operator module approach",
      "body": "import operator\n\ndef is_prime(num):\n    if operator.le(num, 1):\n        return False\n    for i in range(2, operator.add(int(operator.pow(num, 0.5)), 1)):\n        if operator.eq(operator.mod(num, i), 0):\n            return False\n    return True\n\ndef sum_of_primes(lower, upper):\n    total = 0\n    for num in range(lower, operator.add(upper, 1)):\n        if is_prime(num):\n            total += num\n    return total\n\ndef main():\n    lower_limit = int(input('Enter the lower limit: '))\n    upper_limit = int(input('Enter the upper limit: '))\n    prime_sum = sum_of_primes(lower_limit, upper_limit)\n    print(f'The sum of all prime numbers between {lower_limit} and {upper_limit} is: {prime_sum}')\nif operator.eq(__name__, '__main__'):\n    main()"
