    {
      "heading": "standalone insertion-sort helper",
      "body": "def _solution_sorted(iterable, *, key=None, reverse=False):\n    result = []\n    key_function = key or (lambda item: item)\n    for item in iterable:\n        position = 0\n        while position < len(result):\n            before = key_function(result[position])\n            current = key_function(item)\n            if before < current if reverse else before > current:\n                break\n            position += 1\n        result.insert(position, item)\n    return result\n\ndef alphabetically_ordered(sentence):\n    return ' '.join(_solution_sorted(sentence.split()))\nsentence = 'hello caca face'\nprint(alphabetically_ordered(sentence))"
    }
