      "body": "import re\n\ndef extract_extensions_regex(files):\n    result = []\n    for name in files:\n        match = re.search(r'\\.([A-Za-z0-9]+)$', name)\n        if match:\n            result.append(match.group(1))\n    return result\nprint(extract_extensions_regex(['a.py', 'b.txt']))  # Expected: ['py', 'txt']\nprint(extract_extensions_regex(['no_ext', 'x.js']))  # Expected: ['js']"
