  "2080": [
    {
      "heading": "Example 1: simplest reference",
      "body": "import re\n\ndef extract_currency_regex(text):\n    return re.findall(r'\\$\\d+(?:\\.\\d{2})?', text)\nprint(extract_currency_regex('Pay $12 and $4.50'))  # Expected: ['$12', '$4.50']\nprint(extract_currency_regex('none $100'))  # Expected: ['$100']"
    },
    {
      "heading": "compiled regular-expression approach",
      "body": "import re\n\ndef extract_currency_regex(text):\n    return re.compile('\\\\$\\\\d+(?:\\\\.\\\\d{2})?').findall(text)\nprint(extract_currency_regex('Pay $12 and $4.50'))\nprint(extract_currency_regex('none $100'))"
    },
    {
      "heading": "finditer comprehension approach",
      "body": "import re\n\ndef extract_currency_regex(text):\n    return [_match_1.group(0) for _match_1 in re.finditer('\\\\$\\\\d+(?:\\\\.\\\\d{2})?', text)]\nprint(extract_currency_regex('Pay $12 and $4.50'))\nprint(extract_currency_regex('none $100'))"
    },
    {
      "heading": "lambda expression approach",
      "body": "import re\nextract_currency_regex = lambda text: re.findall('\\\\$\\\\d+(?:\\\\.\\\\d{2})?', text)\nprint(extract_currency_regex('Pay $12 and $4.50'))\nprint(extract_currency_regex('none $100'))"
    }
  ],
